## Common patterns

### Password confirmation

A common pattern for password entry with confirmation:

```jsx live-dev
const App = () => {
  const [password, setPassword] = useState<string>('');
  const [confirmPassword, setConfirmPassword] = useState<string>('');

  const passwordsMatch = password === confirmPassword && password !== "";
  const showMismatch = confirmPassword !== "" && !passwordsMatch;

  return (
    <Stack direction="column" gap="400">
      <PasswordInput
        value={password}
        onChange={setPassword}
        placeholder="Enter password"
      />
      <PasswordInput
        value={confirmPassword}
        onChange={setConfirmPassword}
        isInvalid={showMismatch}
        placeholder="Confirm password"
      />
      {showMismatch && (
        <Text fontSize="sm" color="critical.11">
          Passwords do not match
        </Text>
      )}
      {passwordsMatch && (
        <Text fontSize="sm" color="positive.11">
          Passwords match
        </Text>
      )}
    </Stack>
  );
}
```

### Password strength indicator

Integrate with password strength validation:

```jsx live-dev
const App = () => {
  const [password, setPassword] = useState<string>('');

  const getStrength = (pass: string) => {
    if (!pass) return { label: "No password", color: "neutral.11" };
    if (pass.length < 6) return { label: "Weak", color: "critical.11" };
    if (pass.length < 10) return { label: "Medium", color: "warning.11" };
    return { label: "Strong", color: "positive.11" };
  };

  const strength = getStrength(password);

  return (
    <Stack direction="column" gap="400">
      <PasswordInput
        value={password}
        onChange={setPassword}
        placeholder="Enter password"
      />
      <Text fontSize="sm" color={strength.color}>
        Strength: {strength.label}
      </Text>
      <Text fontSize="xs" color="neutral.11">
        Use at least 10 characters for a strong password
      </Text>
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using PasswordInput within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the component renders with expected elements

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { PasswordInput, NimbusProvider } from "@commercetools/nimbus";

describe("PasswordInput - Basic rendering", () => {
  it("renders password input field", () => {
    render(
      <NimbusProvider>
        <PasswordInput aria-label="Password" />
      </NimbusProvider>
    );

    // Verify input is present with password type
    const input = screen.getByLabelText("Password");
    expect(input).toBeInTheDocument();
    expect(input).toHaveAttribute("type", "password");
  });

  it("renders visibility toggle button", () => {
    render(
      <NimbusProvider>
        <PasswordInput aria-label="Password" />
      </NimbusProvider>
    );

    // Verify toggle button is present
    const toggleButton = screen.getByRole("button");
    expect(toggleButton).toBeInTheDocument();
  });

  it("renders with placeholder text", () => {
    render(
      <NimbusProvider>
        <PasswordInput
          aria-label="Password"
          placeholder="Enter your password"
        />
      </NimbusProvider>
    );

    expect(
      screen.getByPlaceholderText("Enter your password")
    ).toBeInTheDocument();
  });
});
```

### Interaction Tests

Test user interactions with the component

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { PasswordInput, NimbusProvider } from "@commercetools/nimbus";

describe("PasswordInput - Interactions", () => {
  it("toggles password visibility when button is clicked", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <PasswordInput aria-label="Password" />
      </NimbusProvider>
    );

    const input = screen.getByLabelText("Password");
    const toggleButton = screen.getByRole("button");

    // Initially type is password
    expect(input).toHaveAttribute("type", "password");

    // Click to show password
    await user.click(toggleButton);
    expect(input).toHaveAttribute("type", "text");

    // Click again to hide password
    await user.click(toggleButton);
    expect(input).toHaveAttribute("type", "password");
  });

  it("calls onChange with entered value", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();
    render(
      <NimbusProvider>
        <PasswordInput aria-label="Password" onChange={handleChange} />
      </NimbusProvider>
    );

    const input = screen.getByLabelText("Password");
    await user.type(input, "Secret123");

    expect(handleChange).toHaveBeenCalled();
    expect(input).toHaveValue("Secret123");
  });

  it("updates value when user types", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <PasswordInput placeholder="Type password" aria-label="Password" />
      </NimbusProvider>
    );

    const input = screen.getByLabelText("Password");
    await user.type(input, "MyPassword123");

    expect(input).toHaveValue("MyPassword123");
  });
});
```

### Testing Controlled Mode

Test controlled component behavior

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { PasswordInput, NimbusProvider } from "@commercetools/nimbus";

describe("PasswordInput - Controlled mode", () => {
  it("displays controlled value", () => {
    render(
      <NimbusProvider>
        <PasswordInput
          value="controlled value"
          onChange={() => {}}
          aria-label="Password"
        />
      </NimbusProvider>
    );

    const input = screen.getByLabelText("Password");
    expect(input).toHaveValue("controlled value");
  });

  it("updates when controlled value changes", () => {
    const { rerender } = render(
      <NimbusProvider>
        <PasswordInput
          value="first value"
          onChange={() => {}}
          aria-label="Password"
        />
      </NimbusProvider>
    );

    expect(screen.getByLabelText("Password")).toHaveValue("first value");

    rerender(
      <NimbusProvider>
        <PasswordInput
          value="second value"
          onChange={() => {}}
          aria-label="Password"
        />
      </NimbusProvider>
    );

    expect(screen.getByLabelText("Password")).toHaveValue("second value");
  });

  it("clears controlled value", async () => {
    const user = userEvent.setup();
    let currentValue = "Test";

    const { rerender } = render(
      <NimbusProvider>
        <PasswordInput
          value={currentValue}
          onChange={(value: string) => {
            currentValue = value;
          }}
          aria-label="Password"
        />
      </NimbusProvider>
    );

    const input = screen.getByLabelText("Password");
    expect(input).toHaveValue("Test");

    await user.clear(input);

    // Rerender with cleared value
    rerender(
      <NimbusProvider>
        <PasswordInput
          value=""
          onChange={(value: string) => {
            currentValue = value;
          }}
          aria-label="Password"
        />
      </NimbusProvider>
    );

    expect(input).toHaveValue("");
  });
});
```

